// file1.cpp
extern int config_value;  // Declared elsewhere
int derived_value = config_value * 2;  // Noncompliant: may use uninitialized value

// file2.cpp
int config_value = 42;  // Definition - initialization order undefined

// Another noncompliant example
struct GlobalObject {
    GlobalObject(int val) : value(val) {}
    int value;
};

GlobalObject obj1(10);
GlobalObject obj2(obj1.value);  // Noncompliant: obj1 may not be initialized yet

// Noncompliant: Cross-translation-unit dependency
// header.h
extern std::string global_name;
extern int global_size;

// file1.cpp
std::string global_name = "example";

// file2.cpp
int global_size = global_name.length();  // Noncompliant: undefined order

compliant:
// Compliant: Using initialization function
int getConfigValue() {
    static int config_value = 42;  // Initialized on first call
    return config_value;
}

int getDerivedValue() {
    static int derived_value = getConfigValue() * 2;
    return derived_value;
}

// Another compliant example using static local variables
struct GlobalObject {
    GlobalObject(int val) : value(val) {}
    int value;
};

GlobalObject& getObj1() {
    static GlobalObject obj(10);
    return obj;
}

GlobalObject& getObj2() {
    static GlobalObject obj(getObj1().value);
    return obj;
}

// Compliant: Using constants or literal initialization
const int BUFFER_SIZE = 1024;  // Constant initialization
const int MAX_ITEMS = 100;
int buffer[BUFFER_SIZE];  // Using constant - safe

// Compliant: Using meyer's singleton pattern
class Configuration {
public:
    static Configuration& getInstance() {
        static Configuration instance;  // Guaranteed initialized on first call
        return instance;
    }

    int getValue() const { return value_; }

private:
    Configuration() : value_(42) {}
    int value_;
};

// Safe access
int derived = Configuration::getInstance().getValue() * 2;
